1040: @Composable
1041: private fun MiniChart(points: List<Float>, color: Color, modifier: Modifier) {
1042:     Canvas(modifier) {
1043:         if (points.size < 2) return@Canvas
1044:         val step = size.width / (points.size - 1)
1045:         val path = Path()
1046:         points.forEachIndexed { index, point ->
1047:             val x = index * step
1048:             val y = size.height * (1f - point)
1049:             if (index == 0) path.moveTo(x, y) else path.lineTo(x, y)
1050:             drawCircle(color, radius = 3.dp.toPx(), center = androidx.compose.ui.geometry.Offset(x, y))
1051:         }
1052:         drawPath(path, color, style = androidx.compose.ui.graphics.drawscope.Stroke(width = 2.dp.toPx(), cap = StrokeCap.Round))
1053:     }
1054: }
