package com.rehealth.genie.features

import com.rehealth.genie.ring.RingMetricType
import com.rehealth.genie.ring.RingUiState
import com.rehealth.genie.ring.data.RingActivityEntity
import com.rehealth.genie.ring.data.RingMeasurementEntity
import java.time.Instant
import java.time.ZoneId

data class Cvd16FeatureState(
    val key: String,
    val label: String,
    val value: String,
    val source: String,
    val available: Boolean,
)

fun RingUiState.cvd16Features(): List<Cvd16FeatureState> {
    val bloodPressure = measurements[RingMetricType.BLOOD_PRESSURE]
    val exerciseDays = exerciseDays(activityHistory, measurementHistory[RingMetricType.STEPS].orEmpty())
    return listOf(
        missing("age", "年龄", "健康采访/档案"),
        missing("gender", "性别", "健康采访/档案"),
        missing("bmi", "BMI", "身高、体重档案"),
        available("sbp", "收缩压", bloodPressure?.primaryValue?.let { "${it.toInt()} mmHg" }, bloodPressure?.source),
        available("dbp", "舒张压", bloodPressure?.secondaryValue?.let { "${it.toInt()} mmHg" }, bloodPressure?.source),
        missing("fasting_glucose", "空腹血糖", "化验单/手动录入"),
        missing("total_cholesterol", "总胆固醇", "化验单/手动录入"),
        missing("ldl", "低密度脂蛋白", "化验单/手动录入"),
        missing("hdl", "高密度脂蛋白", "化验单/手动录入"),
        missing("triglycerides", "甘油三酯", "化验单/手动录入"),
        available("exercise_days", "近 7 日运动天数", exerciseDays?.let { "$it 天" }, "戒指步数/活动记录"),
        missing("smoking", "吸烟情况", "健康采访/档案"),
        missing("drinking", "饮酒情况", "健康采访/档案"),
        missing("diabetes_history", "糖尿病史", "健康采访/档案"),
        missing("hypertension_history", "高血压史", "健康采访/档案"),
        missing("family_history", "家族史", "健康采访/档案"),
    )
}

private fun available(key: String, label: String, value: String?, source: String?) =
    if (value == null) missing(key, label, source ?: "戒指") else Cvd16FeatureState(key, label, value, "真实戒指数据", true)

private fun missing(key: String, label: String, source: String) =
    Cvd16FeatureState(key, label, "待补充", source, false)

private fun exerciseDays(
    activities: List<RingActivityEntity>,
    stepMeasurements: List<RingMeasurementEntity>,
): Int? {
    val cutoff = System.currentTimeMillis() - 6L * 24 * 60 * 60 * 1000
    val activeDates = activities.asSequence()
        .filter { it.startedAt >= cutoff && (it.durationMinutes >= 20 || it.steps >= 7_000) }
        .map { it.startedAt.localDate() }
    val stepDates = stepMeasurements.asSequence()
        .filter { it.measuredAt >= cutoff && it.primaryValue >= 7_000 }
        .map { it.measuredAt.localDate() }
    val dates = (activeDates + stepDates).toSet()
    return dates.size.takeIf { activities.isNotEmpty() || stepMeasurements.isNotEmpty() }
}

private fun Long.localDate() = Instant.ofEpochMilli(this).atZone(ZoneId.systemDefault()).toLocalDate()

