                ) {
                    Column(Modifier.weight(1f)) {
                        Text(SimpleDateFormat("MM-dd HH:mm", Locale.getDefault()).format(Date(record.measuredAt)), color = Ink, fontWeight = FontWeight.Medium)
                        Text("来源：${record.source}", color = Muted, fontSize = 10.sp)
                    }
                    Text(record.valueLabel(metric), color = Mint, fontSize = 17.sp, fontWeight = FontWeight.Bold)
                }
            }
        }
    }
}

private fun RingMetricType.metricLabel(): String = when (this) {
    RingMetricType.HEART_RATE -> "心率"
    RingMetricType.BLOOD_OXYGEN -> "血氧"
    RingMetricType.BLOOD_PRESSURE -> "血压"
    RingMetricType.TEMPERATURE -> "体温"
    RingMetricType.STEPS -> "步数"
    RingMetricType.SLEEP -> "睡眠"
    else -> name
}

private fun RingMeasurementEntity.valueLabel(metric: RingMetricType): String = when (metric) {
    RingMetricType.BLOOD_PRESSURE -> "${primaryValue.toInt()}/${secondaryValue?.toInt() ?: "--"} mmHg"
    RingMetricType.TEMPERATURE -> String.format(Locale.getDefault(), "%.1f °C", primaryValue)
    RingMetricType.BLOOD_OXYGEN -> "${primaryValue.toInt()} %"
    RingMetricType.HEART_RATE -> "${primaryValue.toInt()} bpm"
    RingMetricType.STEPS -> "${primaryValue.toInt()} 步"
    else -> primaryValue.toString()
}

