package com.rehealth.genie.ring

import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Test

class RingMeasurementFreshnessTest {
    private val now = 1_800_000_000_000L

    @Test
    fun onlyConnectedFreshMrdMeasurementsCanBeShownAsLive() {
        assertTrue(isCurrentMrdMeasurement(now - 60_000, "mrd_ring", isConnected = true, now = now))
        assertFalse(isCurrentMrdMeasurement(now - 60_000, "mrd_ring", isConnected = false, now = now))
        assertFalse(isCurrentMrdMeasurement(now - 60_000, "ring_mock", isConnected = true, now = now))
        assertFalse(isCurrentMrdMeasurement(now - LIVE_MEASUREMENT_MAX_AGE_MS - 1, "mrd_ring", isConnected = true, now = now))
    }
}

